// ─────────────────── State ──────────────────────────────────────────────────────────
const allRows = ref<RowItem[]>([...MOCK_DATA]);

const state = reactive({
  loading:     false,
  selectedRow: null as RowItem | null,
  pageSize:    20,
  page:        { first: 0, rows: 20 },
});

const searchParams = reactive({
  userId: '',
  deptName: '',
  eduDateRangeFrom: '',
  eduDateRangeTo: '',
  eduTypeCd: '',
  dupCheckYn: '',
});

// ─────────────────── Computed ───────────────────────────────────────────────────────
const filteredRows = computed<RowItem[]>(() => {
  let rows = allRows.value;
  if (searchParams.userId) rows = rows.filter(r => r.userId.includes(searchParams.userId));
  if (searchParams.deptName) rows = rows.filter(r => r.deptName.includes(searchParams.deptName));
  if (searchParams.eduDateRangeFrom) rows = rows.filter(r => r.eduDateRange >= searchParams.eduDateRangeFrom);
  if (searchParams.eduDateRangeTo)   rows = rows.filter(r => r.eduDateRange <= searchParams.eduDateRangeTo);
  if (searchParams.eduTypeCd) rows = rows.filter(r => r.eduTypeCd === searchParams.eduTypeCd);
  if (searchParams.dupCheckYn) rows = rows.filter(r => r.dupCheckYn === searchParams.dupCheckYn);
  return rows;
});

const pagedRows = computed<RowItem[]>(() =>
  filteredRows.value.slice(state.page.first, state.page.first + state.pageSize)
);

// ─────────────────── Handlers ───────────────────────────────────────────────────────
